class TestCryptoPipelineFailureEscalation(unittest.TestCase):
    def test_triggers_on_extreme_oversold_no_trades(self):
        stats = {"rsi_snapshot": {"BTC/USD": {"today": 14.3}, "ETH/USD": {"today": 19.1}}}
        state = {"strategies": {"crypto-momentum": {"trades_7d": 0}, "crypto-oversold-bounce": {"trades_7d": 0}}}
        fired, reason = heuristic_crypto_pipeline_failure_escalation(stats, state)
        self.assertTrue(fired)
        self.assertIn("CRYPTO-PIPELINE-ESCALATION", reason)

    def test_no_trigger_when_crypto_trades_exist(self):
        stats = {"rsi_snapshot": {"BTC/USD": {"today": 14.3}, "ETH/USD": {"today": 19.1}}}
        state = {"strategies": {"crypto-momentum": {"trades_7d": 1}, "crypto-oversold-bounce": {"trades_7d": 0}}}
        fired, _ = heuristic_crypto_pipeline_failure_escalation(stats, state)
        self.assertFalse(fired)

    def test_no_trigger_when_rsi_normal(self):
        stats = {"rsi_snapshot": {"BTC/USD": {"today": 48.6}, "ETH/USD": {"today": 52.0}}}
        state = {"strategies": {"crypto-momentum": {"trades_7d": 0}, "crypto-oversold-bounce": {"trades_7d": 0}}}
        fired, _ = heuristic_crypto_pipeline_failure_escalation(stats, state)
        self.assertFalse(fired)

    def test_no_trigger_when_rsi_missing(self):
        stats = {"rsi_snapshot": {}}
        state = {"strategies": {"crypto-momentum": {"trades_7d": 0}, "crypto-oversold-bounce": {"trades_7d": 0}}}
        fired, _ = heuristic_crypto_pipeline_failure_escalation(stats, state)
        self.assertFalse(fired)

    def test_no_trigger_eth_rsi_above_threshold(self):
        stats = {"rsi_snapshot": {"BTC/USD": {"today": 15.0}, "ETH/USD": {"today": 26.0}}}
        state = {"strategies": {"crypto-momentum": {"trades_7d": 0}, "crypto-oversold-bounce": {"trades_7d": 0}}}
        fired, _ = heuristic_crypto_pipeline_failure_escalation(stats, state)
        self.assertFalse(fired)
